import{_ as a,o as c,c as r,a2 as t}from"./chunks/framework.BKG_UbFK.js";const p=JSON.parse('{"title":"सुरक्षा","description":"","frontmatter":{},"headers":[],"relativePath":"hi/guide/security.md","filePath":"hi/guide/security.md"}'),i={name:"hi/guide/security.md"};function o(d,e,l,s,n,h){return c(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="सुरक्षा" tabindex="-1">सुरक्षा <a class="header-anchor" href="#सुरक्षा" aria-label="Permalink to &quot;सुरक्षा&quot;">​</a></h1><p>रिलीज़ से पहले Clearance एक समर्पित pre-publication सुरक्षा ऑडिट के साथ-साथ दो follow-up hardening पास से गुजरा। मुख्य बातें: हर अनुमति-प्रदान करने वाले पथ (प्रत्यक्ष अनुदान और role-level syncing दोनों) पर privilege-escalation सीलिंग, deny-प्राथमिकता वाले संदर्भ ओवरराइड, एक allow-list SVG sanitizer, एक सुरक्षित <code>clearance-*</code> अनुमति नेमस्पेस, और guest-safe Blade directives।</p><h2 id="पैनल-एक्सेस-और-सूक्ष्म-स्तरीय-write-अनुमतियाँ" tabindex="-1">पैनल एक्सेस और सूक्ष्म-स्तरीय write अनुमतियाँ <a class="header-anchor" href="#पैनल-एक्सेस-और-सूक्ष्म-स्तरीय-write-अनुमतियाँ" aria-label="Permalink to &quot;पैनल एक्सेस और सूक्ष्म-स्तरीय write अनुमतियाँ&quot;">​</a></h2><p>पूरे पैनल तक पढ़ने की एक्सेस के लिए <code>clearance-access</code> अनुमति आवश्यक है (<code>can()</code> के माध्यम से जांची गई, <code>hasRole()</code> से कभी नहीं)। प्रत्येक सेक्शन पर write ऑपरेशन एक समर्पित, सौंपी जा सकने वाली अनुमति द्वारा नियंत्रित होते हैं - सभी <code>clearance:install</code> द्वारा बनाई गई और <code>super_admin</code> को असाइन की गई:</p><table tabindex="0"><thead><tr><th>अनुमति</th><th>नियंत्रित करती है</th></tr></thead><tbody><tr><td><code>clearance-permissions-write</code></td><td>अनुमतियों को बनाना / संपादित करना / हटाना</td></tr><tr><td><code>clearance-roles-write</code></td><td>भूमिकाओं और उनके अनुमति असाइनमेंट को बनाना / संपादित करना / हटाना</td></tr><tr><td><code>clearance-guards-write</code></td><td>गार्ड्स को बनाना / संपादित करना / हटाना</td></tr><tr><td><code>clearance-settings-write</code></td><td>डिस्प्ले मेटाडेटा, आइकन, रंग, डिफ़ॉल्ट भूमिका को संपादित करना</td></tr><tr><td><code>clearance-users-write</code></td><td>किसी विशिष्ट उपयोगकर्ता के लिए भूमिकाएं असाइन / हटाना</td></tr></tbody></table><p>यदि कोई सूक्ष्म-स्तरीय अनुमति row डेटाबेस में बिल्कुल मौजूद ही नहीं है (एक legacy pre-seeding स्थिति), तो जांच backwards compatibility के लिए <code>clearance-access</code> पर fall back हो जाती है।</p><h2 id="सुरक्षित-clearance-नेमस्पेस" tabindex="-1">सुरक्षित <code>clearance-*</code> नेमस्पेस <a class="header-anchor" href="#सुरक्षित-clearance-नेमस्पेस" aria-label="Permalink to &quot;सुरक्षित `clearance-*` नेमस्पेस&quot;">​</a></h2><p><code>clearance-*</code> अनुमतियाँ आरक्षित हैं: इन्हें पैकेज के अपने install फ्लो के अलावा किसी भी तरह से बनाया, नाम-परिवर्तित, हटाया, या किसी भूमिका में जोड़ा नहीं जा सकता - यहां तक कि किसी <code>super_admin</code> एक्टर द्वारा भी नहीं, स्वयं <code>super_admin</code> भूमिका के लिए भी।</p><h2 id="privilege-escalation-सीलिंग" tabindex="-1">Privilege-escalation सीलिंग <a class="header-anchor" href="#privilege-escalation-सीलिंग" aria-label="Permalink to &quot;Privilege-escalation सीलिंग&quot;">​</a></h2><p>Clearance में हर अनुमति-प्रदान करने वाला पथ एक सीलिंग लागू करता है ताकि कोई एक्टर कभी भी उससे अधिक न दे सके जितना वह स्वयं रखता है:</p><ul><li><strong>सीलिंग भूमिकाएं</strong> - एक भूमिका एक पैरेंट भूमिका घोषित कर सकती है जिसका अनुमति सेट एक ऊपरी सीमा के रूप में कार्य करता है। कोई भी अतिरिक्त अनुमति <code>RoleService::setParent()</code> पर और हर बाद के अनुमति sync पर चुपचाप trim कर दी जाती है - कोई exception नहीं, कोई error message नहीं। किसी पैरेंट से अनुमतियाँ हटाना स्वचालित रूप से हर चाइल्ड में यह हटाव cascade करता है। पूरे ceiling API के लिए देखें <a href="/clearance-docs/hi/features/roles.html">भूमिकाएं</a>।</li><li><strong>Users मॉड्यूल</strong> - भूमिका असाइनमेंट और direct/override अनुमति अनुदान दोनों एक privilege ceiling लागू करते हैं: कोई गैर-<code>super_admin</code> एक्टर अपने खुद के असाइनमेंट को संशोधित नहीं कर सकता, और ऐसी अनुमति नहीं दे सकता जो उसके पास स्वयं नहीं है। देखें <a href="/clearance-docs/hi/features/users.html">उपयोगकर्ता</a>।</li></ul><h2 id="deny-प्राथमिकता-वाले-संदर्भ-ओवरराइड" tabindex="-1">Deny-प्राथमिकता वाले संदर्भ ओवरराइड <a class="header-anchor" href="#deny-प्राथमिकता-वाले-संदर्भ-ओवरराइड" aria-label="Permalink to &quot;Deny-प्राथमिकता वाले संदर्भ ओवरराइड&quot;">​</a></h2><p>प्रति-संदर्भ अनुमति ओवरराइड (<code>clr_ctx_overrides</code>) <code>forced_on</code> और <code>forced_off</code> का समर्थन करते हैं। <code>forced_off</code> हमेशा जीतता है - यहां तक कि किसी वैश्विक भूमिका द्वारा दी गई अनुमति पर भी। ऐसा कोई रास्ता नहीं है जिससे कम प्राथमिकता वाला अनुदान किसी स्पष्ट denial को override कर सके। पूरे resolution क्रम के लिए देखें <a href="/clearance-docs/hi/guide/architecture.html#how-resolution-works">आर्किटेक्चर</a>।</p><h2 id="svg-sanitization" tabindex="-1">SVG sanitization <a class="header-anchor" href="#svg-sanitization" aria-label="Permalink to &quot;SVG sanitization&quot;">​</a></h2><p>हर उपयोगकर्ता-प्रदत्त आइकन (Settings पैनल में भूमिका/गार्ड डिस्प्ले मेटाडेटा) स्टोरेज से पहले और render के समय दोनों बार एक allow-list sanitizer से होकर गुजरता है - upload पर सिर्फ एक बार की जांच नहीं।</p><h2 id="guest-safe-blade-directives" tabindex="-1">Guest-safe Blade directives <a class="header-anchor" href="#guest-safe-blade-directives" aria-label="Permalink to &quot;Guest-safe Blade directives&quot;">​</a></h2><p><code>@canin</code> और <code>@hasrolein</code> दोनों किसी guest उपयोगकर्ता के लिए सुरक्षित रूप से resolve होते हैं (<code>false</code> return करते हैं) - ये कभी throw नहीं करते।</p><h2 id="gate-bypass-एप्लिकेशन-व्यापी-है" tabindex="-1">Gate bypass एप्लिकेशन-व्यापी है <a class="header-anchor" href="#gate-bypass-एप्लिकेशन-व्यापी-है" aria-label="Permalink to &quot;Gate bypass एप्लिकेशन-व्यापी है&quot;">​</a></h2><p><code>super_admin_gate_bypass</code> (डिफ़ॉल्ट <code>false</code>) यह नियंत्रित करता है कि क्या <code>super_admin</code> भूमिका, <code>Gate::before()</code> hook के माध्यम से सभी Laravel <code>can()</code> / <code>Gate::allows()</code> / policy जांचों को globally bypass करती है।</p><div class="warning custom-block"><p class="custom-block-title">पैनल तक सीमित नहीं</p><p>सक्षम होने पर, <code>super_admin</code> रखने वाला कोई भी उपयोगकर्ता एप्लिकेशन-व्यापी सभी Gate जांचों को स्किप कर देता है - न केवल Clearance पैनल की जांचों को। इसे सोच-समझकर सक्षम करें। alias डिटेक्शन और प्रमोशन व्यवहार के लिए <a href="/clearance-docs/hi/features/super-admin.html">सुपर एडमिन</a> देखें।</p></div><h2 id="सुरक्षा-संबंधी-सावधानियां" tabindex="-1">सुरक्षा-संबंधी सावधानियां <a class="header-anchor" href="#सुरक्षा-संबंधी-सावधानियां" aria-label="Permalink to &quot;सुरक्षा-संबंधी सावधानियां&quot;">​</a></h2><ul><li><code>forced_off</code> हमेशा जीतता है - यहां तक कि किसी वैश्विक भूमिका द्वारा दी गई अनुमति पर भी।</li><li>एक सीलिंग भूमिका केवल trim करती है, कभी अनुमति नहीं देती - एक permissive पैरेंट सेट करने से चाइल्ड को खुद-ब-खुद कुछ नहीं मिलता।</li><li>Gate bypass (<code>super_admin_gate_bypass</code>) एप्लिकेशन-व्यापी है, पैनल तक सीमित नहीं।</li><li>Users मॉड्यूल डिफ़ॉल्ट रूप से बंद है (<code>modules.users = false</code>)।</li><li><code>clearance-*</code> अनुमतियाँ install फ्लो के बाहर अछूती रहती हैं, यहां तक कि <code>super_admin</code> के लिए भी।</li><li>किसी नए (fresh) सेटअप पर हमेशा <code>clearance:install</code> चलाएं, सादा <code>migrate</code> नहीं - देखें <a href="/clearance-docs/hi/guide/installation.html">इंस्टॉलेशन</a>।</li></ul><h2 id="संबंधित" tabindex="-1">संबंधित <a class="header-anchor" href="#संबंधित" aria-label="Permalink to &quot;संबंधित&quot;">​</a></h2><ul><li><a href="/clearance-docs/hi/guide/architecture.html">आर्किटेक्चर</a> - resolution प्राथमिकता और <code>clr_*</code> schema</li><li><a href="/clearance-docs/hi/features/roles.html">भूमिकाएं</a> - सीलिंग भूमिकाओं का विस्तृत विवरण</li><li><a href="/clearance-docs/hi/features/users.html">उपयोगकर्ता</a> - भूमिका/अनुमति असाइनमेंट पर privilege ceiling</li><li><a href="/clearance-docs/hi/features/super-admin.html">सुपर एडमिन</a> - Gate bypass और alias detection</li></ul>',24)])])}const f=a(i,[["render",o]]);export{p as __pageData,f as default};
